from flask import Flask, redirect, url_for, session, request
from flask_session import Session
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'
app.config['SESSION_TYPE'] = 'filesystem'
Session(app)

CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://provider.com/oauth2/authorize'
TOKEN_ENDPOINT = 'https://provider.com/oauth2/token'
JWKS_URI = 'https://provider.com/.well-known/jwks.json'

@app.route('/')
def home():
    return 'Welcome to the Flask OpenID Connect app! <a href="/login">Login</a>'

@app.route('/login')
def login():
    authorization_url = f"{AUTHORIZATION_ENDPOINT}?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope=openid email profile"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(TOKEN_ENDPOINT, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
    })
    token_data = token_response.json()
    id_token = token_data['id_token']

    # Decode the id_token
    jwks = requests.get(JWKS_URI).json()
    unverified_header = jwt.get_unverified_header(id_token)
    rsa_public_key = {}
    for key in jwks['keys']:
        if key['kid'] == unverified_header['kid']:
            rsa_public_key = {
                'kty': key['kty'],
                'n': key['n'],
                'e': key['e']
            }
            break

    decoded_token = jwt.decode(id_token, rsa_public_key, algorithms=['RS256'], audience=CLIENT_ID)
    session['user'] = {
        'sub': decoded_token['sub'],
        'email': decoded_token['email'],
        'name': decoded_token['name']
    }
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    user_info = session['user']
    return f"Hello, {user_info['name']}! Your email is {user_info['email']}."

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)